317:     public CompletedCheckpoint finalizeCheckpoint(
318:             CheckpointsCleaner checkpointsCleaner, Runnable postCleanup, Executor executor)
319:             throws IOException {
320: 
321:         synchronized (lock) {
322:             checkState(!isDisposed(), "checkpoint is discarded");
323:             checkState(
324:                     isFullyAcknowledged(),
325:                     "Pending checkpoint has not been fully acknowledged yet");
326: 
327:             // make sure we fulfill the promise with an exception if something fails
328:             try {
329:                 checkpointPlan.fulfillFinishedTaskStatus(operatorStates);
330: 
331:                 // write out the metadata
332:                 final CheckpointMetadata savepoint =
333:                         new CheckpointMetadata(
334:                                 checkpointId, operatorStates.values(), masterStates, props);
335:                 final CompletedCheckpointStorageLocation finalizedLocation;
336: 
337:                 try (CheckpointMetadataOutputStream out =
338:                         targetLocation.createMetadataOutputStream()) {
339:                     Checkpoints.storeCheckpointMetadata(savepoint, out);
340:                     finalizedLocation = out.closeAndFinalizeCheckpoint();
341:                 }
342: 
343:                 CompletedCheckpoint completed =
344:                         new CompletedCheckpoint(
345:                                 jobId,
346:                                 checkpointId,
347:                                 checkpointTimestamp,
348:                                 System.currentTimeMillis(),
349:                                 operatorStates,
350:                                 masterStates,
351:                                 props,
352:                                 finalizedLocation,
353:                                 toCompletedCheckpointStats(finalizedLocation));
354: 
355:                 // mark this pending checkpoint as disposed, but do NOT drop the state
356:                 dispose(false, checkpointsCleaner, postCleanup, executor);
357: 
358:                 return completed;
359:             } catch (Throwable t) {
360:                 onCompletionPromise.completeExceptionally(t);
361:                 ExceptionUtils.rethrowIOException(t);
362:                 return null; // silence the compiler
363:             }
364:         }
365:     }
