151:         Optional<BufferOrEvent> next = inputGate.pollNext();
152: 
153:         if (!next.isPresent()) {
154:             return handleEmptyBuffer();
155:         }
156: 
157:         BufferOrEvent bufferOrEvent = next.get();
158: 
159:         if (bufferOrEvent.isEvent()) {
160:             return handleEvent(bufferOrEvent);
161:         } else if (bufferOrEvent.isBuffer()) {
162:             /**
163:              * https://issues.apache.org/jira/browse/FLINK-19537 This is not entirely true, as it's
164:              * ignoring the buffer/bytes accumulated in the record deserializers. If buffer is
165:              * processed here, it doesn't mean it was fully processed (so we can over estimate the
166:              * amount of processed bytes). On the other hand some records/bytes might be processed
167:              * without polling anything from this {@link CheckpointedInputGate} (underestimating the
168:              * amount of processed bytes). All in all this should have been calculated on the {@link
169:              * StreamTaskNetworkInput} level, where we have an access to the records deserializers.
170:              * However the current is on average accurate and it might be just good enough (at least
171:              * for the time being).
172:              */
173:             barrierHandler.addProcessedBytes(bufferOrEvent.getBuffer().getSize());
174:         }
175:         return next;
176:     }
