178:     private Optional<BufferOrEvent> handleEvent(BufferOrEvent bufferOrEvent) throws IOException {
179:         Class<? extends AbstractEvent> eventClass = bufferOrEvent.getEvent().getClass();
180:         if (eventClass == CheckpointBarrier.class) {
181:             CheckpointBarrier checkpointBarrier = (CheckpointBarrier) bufferOrEvent.getEvent();
182:             barrierHandler.processBarrier(checkpointBarrier, bufferOrEvent.getChannelInfo(), false);
183:         } else if (eventClass == CancelCheckpointMarker.class) {
184:             barrierHandler.processCancellationBarrier(
185:                     (CancelCheckpointMarker) bufferOrEvent.getEvent(),
186:                     bufferOrEvent.getChannelInfo());
187:         } else if (eventClass == EndOfData.class) {
188:             inputGate.acknowledgeAllRecordsProcessed(bufferOrEvent.getChannelInfo());
189:         } else if (eventClass == EndOfPartitionEvent.class) {
190:             barrierHandler.processEndOfPartition(bufferOrEvent.getChannelInfo());
191:         } else if (eventClass == EventAnnouncement.class) {
192:             EventAnnouncement eventAnnouncement = (EventAnnouncement) bufferOrEvent.getEvent();
193:             AbstractEvent announcedEvent = eventAnnouncement.getAnnouncedEvent();
194:             checkState(
195:                     announcedEvent instanceof CheckpointBarrier,
196:                     "Only CheckpointBarrier announcement are currently supported, but found [%s]",
197:                     announcedEvent);
198:             CheckpointBarrier announcedBarrier = (CheckpointBarrier) announcedEvent;
199:             barrierHandler.processBarrierAnnouncement(
200:                     announcedBarrier,
201:                     eventAnnouncement.getSequenceNumber(),
202:                     bufferOrEvent.getChannelInfo());
203:         } else if (bufferOrEvent.getEvent().getClass() == EndOfOutputChannelStateEvent.class) {
204:             upstreamRecoveryTracker.handleEndOfRecovery(bufferOrEvent.getChannelInfo());
205:         }
206:         return Optional.of(bufferOrEvent);
207:     }
