246:             if (targetChannelCount == 1) {
247:                 markAlignmentStartAndEnd(barrier.getId(), barrier.getTimestamp());
248:             } else {
249:                 markAlignmentStart(barrier.getId(), barrier.getTimestamp());
250:             }
251:         }
