259:         }
260: 
261:         try {
262:             currentState = stateTransformer.apply(currentState);
263:         } catch (CheckpointException e) {
264:             abortInternal(currentCheckpointId, e);
265:         } catch (Exception e) {
266:             ExceptionUtils.rethrowIOException(e);
267:         }
