217:     @Override
218:     public void abortCheckpointOnBarrier(
219:             long checkpointId, CheckpointException cause, OperatorChain<?, ?> operatorChain)
220:             throws IOException {
221:         LOG.debug("Aborting checkpoint via cancel-barrier {} for task {}", checkpointId, taskName);
222:         lastCheckpointId = Math.max(lastCheckpointId, checkpointId);
223:         Iterator<Long> iterator = abortedCheckpointIds.iterator();
224:         while (iterator.hasNext()) {
225:             long next = iterator.next();
226:             if (next < lastCheckpointId) {
227:                 iterator.remove();
228:             } else {
229:                 break;
230:             }
231:         }
232: 
233:         checkpointStorage.clearCacheFor(checkpointId);
234: 
235:         channelStateWriter.abort(checkpointId, cause, true);
236: 
237:         // notify the coordinator that we decline this checkpoint
238:         env.declineCheckpoint(checkpointId, cause);
239: 
240:         actionExecutor.runThrowing(
241:                 () -> {
242:                     if (checkpointId == alignmentCheckpointId) {
243:                         cancelAlignmentTimer();
244:                     }
245:                     // notify all downstream operators that they should not wait for a barrier from
246:                     // us and abort checkpoint.
247:                     operatorChain.abortCheckpoint(checkpointId, cause);
248:                     operatorChain.broadcastEvent(new CancelCheckpointMarker(checkpointId));
249:                 });
250:     }
