380:     private void registerAlignmentTimer(
381:             long checkpointId,
382:             OperatorChain<?, ?> operatorChain,
383:             CheckpointBarrier checkpointBarrier) {
384:         // The timer isn't triggered when the checkpoint completes quickly, so cancel timer here.
385:         cancelAlignmentTimer();
