397:                             } catch (Exception e) {
398:                                 ExceptionUtils.rethrowIOException(e);
399:                             }
400:                             alignmentTimer = null;
401:                             return null;
402:                         },
403:                         Duration.ofMillis(timerDelay));
404:         alignmentCheckpointId = checkpointId;
